#include <cstdint>
#include <stdexcept>

template<size_t block_size = 1024>
std::vector<uint8_t> peek_data_from_buffer(const hexi::dynamic_buffer<block_size>& buffer, size_t bytes_to_peek) {
    // Handle the case where the requested bytes exceed the buffer size
    if (bytes_to_peek > buffer.size()) {
        throw std::out_of_range("Requested bytes exceed buffer size");
    }

    // Create a vector to hold the peeked data
    std::vector<uint8_t> result(bytes_to_peek);

    // Use the copy method of dynamic_buffer to copy data without advancing read pointer
    buffer.copy(result.data(), bytes_to_peek);

    return result;
}
```

